import React, { useState, useEffect } from 'react';
import './SetPassword.css';

const SetPassword = () => {
  const [password, setPassword] = useState('');
  const [confirm, setConfirm] = useState('');
  const [status, setStatus] = useState('validating'); // validating | valid | invalid | success | error
  const [hospitalName, setHospitalName] = useState('');
  const [message, setMessage] = useState('');

  const token = new URLSearchParams(window.location.search).get('token');

  useEffect(() => {
    if (!token) {
      setStatus('invalid');
      setMessage('No invitation token found.');
      return;
    }
    fetch(`http://localhost:9000/api/hospital/invite/${token}`)
      .then(r => r.json())
      .then(data => {
        if (data.valid) {
          setHospitalName(data.hospitalName);
          setStatus('valid');
        } else {
          setStatus('invalid');
          setMessage(data.message || 'Invalid or expired link.');
        }
      })
      .catch(() => {
        setStatus('invalid');
        setMessage('Could not validate the invitation link.');
      });
  }, [token]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (password !== confirm) {
      setMessage('Passwords do not match.');
      return;
    }
    if (password.length < 8) {
      setMessage('Password must be at least 8 characters.');
      return;
    }
    setMessage('');
    try {
      const res = await fetch('http://localhost:9000/api/hospital/set-password', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ token, password })
      });
      const data = await res.json();
      if (res.ok) {
        setStatus('success');
      } else {
        setMessage(data.message || 'Something went wrong.');
      }
    } catch {
      setMessage('Network error. Please try again.');
    }
  };

  if (status === 'validating') {
    return <div className="sp-container"><p>Validating your invitation link...</p></div>;
  }

  if (status === 'invalid') {
    return (
      <div className="sp-container">
        <div className="sp-card sp-error">
          <h2>Invalid Link</h2>
          <p>{message}</p>
        </div>
      </div>
    );
  }

  if (status === 'success') {
    return (
      <div className="sp-container">
        <div className="sp-card sp-success">
          <h2>Password Set Successfully</h2>
          <p>Your hospital admin account is now active. You can log in to the HealthMandala portal.</p>
        </div>
      </div>
    );
  }

  return (
    <div className="sp-container">
      <div className="sp-card">
        <h2>Set Your Password</h2>
        <p className="sp-subtitle">Welcome, <strong>{hospitalName}</strong>. Create a password to activate your account.</p>
        <form onSubmit={handleSubmit}>
          <div className="sp-field">
            <label>New Password</label>
            <input
              type="password"
              value={password}
              onChange={e => setPassword(e.target.value)}
              placeholder="Minimum 8 characters"
              required
            />
          </div>
          <div className="sp-field">
            <label>Confirm Password</label>
            <input
              type="password"
              value={confirm}
              onChange={e => setConfirm(e.target.value)}
              placeholder="Re-enter your password"
              required
            />
          </div>
          {message && <p className="sp-message">{message}</p>}
          <button type="submit" className="sp-button">Activate Account</button>
        </form>
      </div>
    </div>
  );
};

export default SetPassword;
